type InspectorSectionProps = {
  sectionId: string;
  title: string;
  collapsed: boolean;
  onToggle: (sectionId: string) => void;
  children: ReactNode;
  className?: string;
};

function InspectorSection({ sectionId, title, collapsed, onToggle, children, className }: InspectorSectionProps) {
  return (
    <div className={`inspector-block${className ? ` ${className}` : ""}`}>
      <button
        type="button"
        className={`inspector-block-header ${collapsed ? "collapsed" : ""}`}
        aria-expanded={!collapsed}
        onClick={() => onToggle(sectionId)}
      >
        <span className={`inspector-block-chevron ${collapsed ? "collapsed" : ""}`} aria-hidden="true" />
        <span className="inspector-block-title">{title}</span>
      </button>
      {!collapsed ? <div className="inspector-block-content">{children}</div> : null}
    </div>
  );
}

