function normalizeTooltipText(raw: string): string {
  return raw.replace(/\s+/g, " ").replace(/^[✓✔]\s*/, "").trim();
}

function tooltipFromLabel(control: HTMLElement): string {
  const label = control.closest("label");
  if (!label) {
    return "";
  }
  const clone = label.cloneNode(true) as HTMLElement;
  clone.querySelectorAll("button, input, select, textarea, datalist").forEach((node) => node.remove());
  return normalizeTooltipText(clone.textContent ?? "");
}

function inferTooltip(control: HTMLElement): string {
  const ariaLabel = normalizeTooltipText(control.getAttribute("aria-label") ?? "");
  if (ariaLabel) {
    return ariaLabel;
  }
  if (control instanceof HTMLInputElement || control instanceof HTMLTextAreaElement) {
    const placeholder = normalizeTooltipText(control.placeholder ?? "");
    if (placeholder) {
      return placeholder;
    }
  }
  const labelText = tooltipFromLabel(control);
  if (labelText) {
    return labelText;
  }
  return normalizeTooltipText(control.textContent ?? "");
}

function applyMissingTooltips(root: HTMLElement, enabled: boolean): void {
  const controls = root.querySelectorAll<HTMLElement>(
    "button, a, select, input:not([type='hidden']), textarea"
  );
  controls.forEach((control) => {
    const wasAutoAssigned = control.getAttribute("data-auto-tooltip") === "true";
    if (!enabled) {
      if (wasAutoAssigned) {
        control.removeAttribute("title");
        control.removeAttribute("data-auto-tooltip");
      }
      return;
    }
    if (control.hasAttribute("title") && !wasAutoAssigned) {
      return;
    }
    const tooltip = inferTooltip(control);
    if (!tooltip) {
      return;
    }
    control.setAttribute("title", tooltip);
    control.setAttribute("data-auto-tooltip", "true");
  });
}

function updateComponent(
  layout: LayoutDefinition,
  componentId: string,
  updater: (component: LayoutComponent) => LayoutComponent
): LayoutDefinition {
  return {
    ...layout,
    components: layout.components.map((component) =>
      component.id === componentId ? updater(component) : component
    )
  };
}

function cloneComponentForClipboard(component: LayoutComponent): LayoutComponent {
  return {
    ...component,
    binding: component.binding ? { ...component.binding } : undefined,
    props: { ...component.props },
    events: component.events
      ? {
          ...component.events,
          onClick: component.events.onClick ? { ...component.events.onClick } : undefined
        }
      : undefined
  };
}

function createFieldComponentWithLabel(
  fieldName: string,
  preferences?: FieldDragPreferences,
  tableOccurrence?: string
): LayoutComponent {
  const placement = preferences?.placement ?? "side-by-side";
  const controlType = preferences?.controlType ?? "text";
  const labelPlacement: NonNullable<LayoutComponent["props"]["labelPlacement"]> =
    placement === "stacked" ? "top" : placement === "field-only" ? "none" : "left";
  const shouldShowLabel = labelPlacement !== "none";

  const component = createComponent("field");
  component.binding = {
    ...component.binding,
    field: fieldName,
    ...(tableOccurrence ? { tableOccurrence } : {})
  };
  component.props = {
    ...component.props,
    label: shouldShowLabel ? fieldName : "",
    placeholder: fieldName,
    controlType,
    labelPlacement
  };
  component.position = {
    ...component.position,
    width: placement === "field-only" ? 260 : 360,
    height: placement === "stacked" ? 64 : 42
  };
  return component;
}

function normalizeFieldCatalog(fields: Array<FieldCatalogEntry | string>): FieldCatalogEntry[] {
  const normalizedByName = new Map<string, FieldCatalogEntry>();
  for (const fieldEntry of fields) {
    if (typeof fieldEntry === "string") {
      const name = fieldEntry.trim();
      if (!name) {
        continue;
      }
      if (!normalizedByName.has(name)) {
        normalizedByName.set(name, { name, type: "Text" });
      }
      continue;
    }

    const name = String(fieldEntry.name ?? "").trim();
    if (!name) {
      continue;
    }
    const type = String(fieldEntry.type ?? "Text").trim() || "Text";
    normalizedByName.set(name, {
      name,
      type
    });
  }

  return [...normalizedByName.values()].sort((a, b) => a.name.localeCompare(b.name));
}

function normalizeRelationshipGraphTables(
  tables: RelationshipGraphTable[] | undefined
): RelationshipGraphTable[] {
  if (!Array.isArray(tables) || tables.length === 0) {
    return [];
  }
  const normalized = new Map<string, RelationshipGraphTable>();
  for (let index = 0; index < tables.length; index += 1) {
    const table = tables[index];
    const id = String(table?.id ?? "").trim();
    const name = String(table?.name ?? "").trim();
    const key = id || `name:${name.toLowerCase()}`;
    if (!key || !name) {
      continue;
    }
    const creationIndex =
      Number.isFinite(Number(table?.creationIndex)) && Number(table?.creationIndex) > 0
        ? Number(table.creationIndex)
        : index + 1;
    normalized.set(key, {
      id: id || `${creationIndex}`,
      name,
      source: String(table?.source ?? "FileMaker").trim() || "FileMaker",
      comment: String(table?.comment ?? "").trim(),
      creationIndex
    });
  }
  return [...normalized.values()];
}

function normalizeRelationshipOperator(operator: string): string {
  const normalized = operator.trim().toLowerCase();
  if (!normalized || normalized === "equal" || normalized === "equals") {
    return "=";
  }
  if (normalized === "notequal" || normalized === "not equal") {
    return "<>";
  }
  if (normalized === "greaterthan") {
    return ">";
  }
  if (normalized === "greaterthanorequal") {
    return ">=";
  }
  if (normalized === "lessthan") {
    return "<";
  }
  if (normalized === "lessthanorequal") {
    return "<=";
  }
  return operator.trim();
}

function relationshipTypeLabel(predicates: RelationshipJoinPredicate[]): string {
  if (predicates.length === 0) {
    return "Join";
  }
  const operators = [...new Set(predicates.map((predicate) => normalizeRelationshipOperator(predicate.operator)))];
  if (operators.length === 1) {
    return `Match (${operators[0]})`;
  }
  return `Compound (${operators.join(", ")})`;
}

function normalizeLayoutFolderGroups(
  groups: Array<{ folder: string | null; layouts: string[] }> | undefined
): Array<{ folder: string | null; layouts: string[] }> {
  if (!groups || groups.length === 0) {
    return [];
  }
  const normalizedGroups: Array<{ folder: string | null; layouts: string[] }> = [];
  for (const group of groups) {
    const layouts = Array.isArray(group.layouts)
      ? [...new Set(group.layouts.map((name) => String(name ?? "").trim()).filter((name) => name.length > 0))]
      : [];
    if (layouts.length === 0) {
      continue;
    }
    const folderName = typeof group.folder === "string" ? group.folder.trim() : "";
    normalizedGroups.push({
      folder: folderName ? folderName : null,
      layouts
    });
  }
  return normalizedGroups;
}

function toLayoutSlug(value: string): string {
  const slug = value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return slug || "layout";
}

function nextSuggestedLayoutName(existingNames: string[]): string {
  let highest = 0;
  for (const name of existingNames) {
    const match = name.trim().match(/^layout\s*#\s*(\d+)$/i);
    if (!match) {
      continue;
    }
    const numeric = Number.parseInt(match[1] ?? "", 10);
    if (Number.isFinite(numeric) && numeric > highest) {
      highest = numeric;
    }
  }
  return `Layout #${highest + 1}`;
}

function serializeLayoutPayload(layout: LayoutDefinition, workspaceId?: string): string {
  const seen = new WeakSet<object>();
  return JSON.stringify(
    {
      layout,
      ...(workspaceId ? { workspaceId } : {})
    },
    (_key, value: unknown) => {
      if (typeof value === "bigint") {
        return value.toString();
      }
      if (typeof value === "number" && !Number.isFinite(value)) {
        return 0;
      }
      if (typeof value === "function" || typeof value === "symbol") {
        return undefined;
      }
      if (value instanceof Map) {
        return Object.fromEntries(value);
      }
      if (value instanceof Set) {
        return [...value];
      }
      if (value && typeof value === "object") {
        if (seen.has(value as object)) {
          return undefined;
        }
        seen.add(value as object);
      }
      return value;
    }
  );
}

function relatedTableOccurrenceFromFieldName(fieldName: string | undefined): string | null {
  if (!fieldName) {
    return null;
  }
  const marker = fieldName.indexOf("::");
  if (marker < 1) {
    return null;
  }
  const relation = fieldName.slice(0, marker).trim();
  return relation.length > 0 ? relation : null;
}

function unqualifiedFieldName(fieldName: string): string {
  const trimmed = fieldName.trim();
  if (!trimmed.includes("::")) {
    return trimmed;
  }
  const parts = trimmed.split("::");
  return (parts.slice(1).join("::") || parts[parts.length - 1] || trimmed).trim();
}

function isLikelyContainerFieldName(fieldName: string | undefined): boolean {
  const normalized = (fieldName ?? "").trim().toLowerCase();
  if (!normalized) {
    return false;
  }
  return (
    normalized.includes("container") ||
    normalized.includes("image") ||
    normalized.includes("photo") ||
    normalized.includes("picture") ||
    normalized.includes("logo") ||
    normalized.includes("document")
  );
}

function escapeXmlText(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function wrapCData(value: string): string {
  return `<![CDATA[${value.replaceAll("]]>", "]]]]><![CDATA[>")}]]>`;
}

function fieldEntryMatchesTableOccurrence(
  fieldName: string,
  tableOccurrence: string,
  defaultTableOccurrence: string
): boolean {
  const trimmedName = fieldName.trim();
  if (!trimmedName) {
    return false;
  }
  if (trimmedName.includes("::")) {
    const relation = relatedTableOccurrenceFromFieldName(trimmedName);
    return Boolean(relation && relation.toLowerCase() === tableOccurrence.trim().toLowerCase());
  }
  return tableOccurrence.trim().toLowerCase() === defaultTableOccurrence.trim().toLowerCase();
}

function fieldsForTableOccurrence(
  fields: FieldCatalogEntry[],
  tableOccurrence: string,
  defaultTableOccurrence: string
): FieldCatalogEntry[] {
  const normalizedTarget = tableOccurrence.trim();
  const normalizedDefault = defaultTableOccurrence.trim();
  if (!normalizedTarget) {
    return [];
  }

  const byName = new Map<string, FieldCatalogEntry>();
  for (const field of fields) {
    if (!fieldEntryMatchesTableOccurrence(field.name, normalizedTarget, normalizedDefault)) {
      continue;
    }
    const strippedName = unqualifiedFieldName(field.name);
    if (!strippedName) {
      continue;
    }
    const existing = byName.get(strippedName);
    if (!existing) {
      byName.set(strippedName, { name: strippedName, type: field.type });
      continue;
    }
    if (existing.type === "Text" && field.type !== "Text") {
      byName.set(strippedName, { name: strippedName, type: field.type });
    }
  }

  return [...byName.values()].sort((a, b) => a.name.localeCompare(b.name));
}

function resolveBoundFieldValue(
  record: Record<string, unknown> | null,
  fieldName: string | undefined,
  tableOccurrence: string | undefined
): unknown {
  if (!record || !fieldName) {
    return "";
  }

  const normalizedField = fieldName.trim();
  const normalizedFieldLower = normalizedField.toLowerCase();
  if (!normalizedField) {
    return "";
  }

  if (record[normalizedField] != null) {
    return record[normalizedField];
  }

  for (const [key, value] of Object.entries(record)) {
    if (key.trim().toLowerCase() === normalizedFieldLower && value != null) {
      return value;
    }
  }

  const normalizedTableOccurrence = (tableOccurrence ?? "").trim().toLowerCase();
  const tokenUnqualified = unqualifiedFieldName(normalizedField).toLowerCase();

  if (normalizedTableOccurrence) {
    const qualified = `${tableOccurrence}::${normalizedField}`.trim();
    if (record[qualified] != null) {
      return record[qualified];
    }

    for (const [key, value] of Object.entries(record)) {
      const keyTrimmed = key.trim();
      if (!keyTrimmed.includes("::") || value == null) {
        continue;
      }
      const relation = relatedTableOccurrenceFromFieldName(keyTrimmed)?.toLowerCase() ?? "";
      if (relation !== normalizedTableOccurrence) {
        continue;
      }
      if (unqualifiedFieldName(keyTrimmed).toLowerCase() === tokenUnqualified) {
        return value;
      }
    }
  }

  if (record[tokenUnqualified] != null) {
    return record[tokenUnqualified];
  }

  for (const [key, value] of Object.entries(record)) {
    if (unqualifiedFieldName(key).toLowerCase() === tokenUnqualified && value != null) {
      return value;
    }
  }

  return "";
}

function normalizeTabControlLabelsForSetup(labels: string[]): string[] {
  const normalized = labels
    .map((label) => label.trim())
    .filter((label) => label.length > 0)
    .slice(0, 24);
  return normalized.length > 0 ? normalized : ["Tab 1"];
}

function makeUniqueTabControlLabelForSetup(candidate: string, labels: string[], excludeIndex = -1): string {
  const base = candidate.trim() || "Tab";
  let next = base;
  let suffix = 2;
  const isTaken = (value: string) =>
    labels.some(
      (label, index) =>
        index !== excludeIndex && label.trim().toLowerCase() === value.trim().toLowerCase()
    );
  while (isTaken(next)) {
    next = `${base} ${suffix}`;
    suffix += 1;
  }
  return next;
}

function normalizeSlideControlLabelsForSetup(labels: string[]): string[] {
  const normalized = labels
    .map((label) => label.trim())
    .filter((label) => label.length > 0)
    .slice(0, 24);
  if (normalized.length > 0) {
    return normalized;
  }
  return ["Slide 1", "Slide 2", "Slide 3"];
}

function joinWebViewerUrlParts(...parts: Array<string | undefined>): string {
  return parts
    .map((part) => (part ?? "").trim())
    .filter((part) => part.length > 0)
    .join(" ");
}

function buildWebViewerTemplateFromPreset(presetId: string, values: Record<string, string>): string {
  const read = (key: string) => (values[key] ?? "").trim();
  if (presetId === "custom") {
    return read("url");
  }
  if (presetId === "google-maps-us" || presetId === "google-maps-can") {
    const query = joinWebViewerUrlParts(
      read("address"),
      read("city"),
      read("state") || read("province"),
      read("zipCode") || read("postalCode"),
      read("country")
    );
    return query ? `https://local.google.com/maps?q=${query}` : "https://local.google.com/maps";
  }
  if (presetId === "google-web-search-us") {
    const query = read("query");
    return query ? `https://www.google.com/search?q=${query}` : "https://www.google.com";
  }
  if (presetId === "mapquest") {
    const query = joinWebViewerUrlParts(read("address"), read("city"), read("state"), read("country"));
    return query ? `https://www.mapquest.com/search/results?query=${query}` : "https://www.mapquest.com";
  }
  if (presetId === "wikipedia") {
    const article = read("article");
    return article ? `https://en.wikipedia.org/wiki/${article}` : "https://en.wikipedia.org";
  }
  if (presetId === "fedex") {
    const trackingNumber = read("trackingNumber");
    return trackingNumber
      ? `https://www.fedex.com/fedextrack/?trknbr=${trackingNumber}`
      : "https://www.fedex.com/en-us/tracking.html";
  }
  return read("url");
}

function axisSnap(
  currentStart: number,
  size: number,
  targets: number[],
  threshold: number
): { start: number; guide: number | null } {
  const points = [currentStart, currentStart + size / 2, currentStart + size];
  let bestDiff = threshold + 1;
  let bestGuide: number | null = null;
  let bestStart = currentStart;

  for (const target of targets) {
    for (let pointIndex = 0; pointIndex < points.length; pointIndex += 1) {
      const point = points[pointIndex];
      const diff = Math.abs(point - target);
      if (diff >= bestDiff || diff > threshold) {
        continue;
      }
      bestDiff = diff;
      bestGuide = target;
      if (pointIndex === 0) {
        bestStart = target;
      } else if (pointIndex === 1) {
        bestStart = target - size / 2;
      } else {
        bestStart = target - size;
      }
    }
  }

  return {
    start: bestStart,
    guide: bestGuide
  };
}

function numberValue(value: unknown, fallback: number): number {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function majorGridStep(minorGridStep: number): number {
  return Math.max(1, minorGridStep * 4);
}

type RulerTick = {
  value: number;
  strength: "minor" | "medium" | "major";
  label: string | null;
};

function buildRulerTicks(
  length: number,
  minorStep = 10,
  mediumStep = 50,
  majorStep = 100
): RulerTick[] {
  const safeLength = Math.max(0, Math.floor(length));
  const ticks: RulerTick[] = [];
  for (let value = 0; value <= safeLength; value += minorStep) {
    const isMajor = value % majorStep === 0;
    const isMedium = !isMajor && value % mediumStep === 0;
    ticks.push({
      value,
      strength: isMajor ? "major" : isMedium ? "medium" : "minor",
      label: isMajor ? String(value) : null
    });
  }
  if (ticks.length === 0 || ticks[ticks.length - 1].value !== safeLength) {
    const isMajor = safeLength % majorStep === 0;
    const isMedium = !isMajor && safeLength % mediumStep === 0;
    ticks.push({
      value: safeLength,
      strength: isMajor ? "major" : isMedium ? "medium" : "minor",
      label: isMajor ? String(safeLength) : null
    });
  }
  return ticks;
}

function cssFontWeight(weight: LayoutComponent["props"]["fontWeight"]): CSSProperties["fontWeight"] {
  if (weight === "bold" || weight === "boldItalic") {
    return 700;
  }
  return 400;
}

function cssFontStyle(weight: LayoutComponent["props"]["fontWeight"]): CSSProperties["fontStyle"] {
  if (weight === "italic" || weight === "boldItalic") {
    return "italic";
  }
  return "normal";
}

function resolveFillStyle(
  component: LayoutComponent,
  options?: {
    defaultFillType?: "none" | "solid" | "gradient" | "image";
    defaultFillColor?: string;
  }
): CSSProperties {
  const fillType = component.props.fillType ?? options?.defaultFillType ?? "solid";
  const fallbackColor = options?.defaultFillColor;
  const fillColor = component.props.fillColor || fallbackColor;

  if (fillType === "none") {
    return {
      background: "transparent",
      backgroundImage: "none"
    };
  }

  if (fillType === "gradient") {
    const start = component.props.fillGradientStartColor || fillColor || "#f8fafc";
    const end = component.props.fillGradientEndColor || fillColor || "#e2e8f0";
    const rawAngle = Number(component.props.fillGradientAngle ?? 180);
    const safeAngle = Number.isFinite(rawAngle) ? Math.max(0, Math.min(360, Math.round(rawAngle))) : 180;
    return {
      background: `linear-gradient(${safeAngle}deg, ${start} 0%, ${end} 100%)`
    };
  }

  if (fillType === "image") {
    const imageUrl = (component.props.fillImageUrl ?? "").trim();
    if (imageUrl.length > 0) {
      const escaped = imageUrl.replace(/"/g, '\\"');
      return {
        backgroundColor: fillColor || "#f8fafc",
        backgroundImage: `url("${escaped}")`,
        backgroundSize: "cover",
        backgroundRepeat: "no-repeat",
        backgroundPosition: "center"
      };
    }
    return {
      background: fillColor || "#f8fafc"
    };
  }

  return {
    background: fillColor || undefined
  };
}

function componentBodyStyle(component: LayoutComponent): CSSProperties {
  const lineSpacingValue = numberValue(component.props.lineSpacingHeight ?? component.props.lineSpacing, 1);
  const lineSpacingUnits = component.props.lineSpacingUnits ?? "lines";
  const indentLeft = numberValue(component.props.indentLeft, 0);
  const indentRight = numberValue(component.props.indentRight, 0);
  const indentFirstLine = numberValue(component.props.indentFirstLine, 0);
  return {
    ...resolveFillStyle(component),
    borderStyle: component.props.lineStyle === "none" ? "none" : component.props.lineStyle || undefined,
    borderColor: component.props.lineColor || undefined,
    borderWidth: component.props.lineStyle === "none" ? 0 : numberValue(component.props.lineWidth, 0),
    borderRadius: numberValue(component.props.cornerRadius, 0),
    paddingTop: numberValue(component.props.paddingTop, 2),
    paddingRight: numberValue(component.props.paddingRight, 4) + indentRight,
    paddingBottom: numberValue(component.props.paddingBottom, 2),
    paddingLeft: numberValue(component.props.paddingLeft, 4) + indentLeft,
    color: component.props.textColor || undefined,
    fontFamily: component.props.fontFamily || undefined,
    fontSize: numberValue(component.props.fontSize, 14),
    fontWeight: cssFontWeight(component.props.fontWeight),
    fontStyle: cssFontStyle(component.props.fontWeight),
    textDecoration: component.props.textUnderline ? "underline" : undefined,
    textAlign: component.props.textAlign || undefined,
    lineHeight: lineSpacingUnits === "pt" ? `${lineSpacingValue}px` : lineSpacingValue,
    textIndent: indentFirstLine === 0 ? undefined : `${indentFirstLine}px`,
    boxShadow: component.props.effectOuterShadow ? "0 4px 10px rgba(15, 23, 42, 0.25)" : undefined
  };
}

function fieldValueStyle(component: LayoutComponent): CSSProperties {
  const lineSpacingValue = numberValue(component.props.lineSpacingHeight ?? component.props.lineSpacing, 1);
  const lineSpacingUnits = component.props.lineSpacingUnits ?? "lines";
  const indentLeft = numberValue(component.props.indentLeft, 0);
  const indentRight = numberValue(component.props.indentRight, 0);
  const indentFirstLine = numberValue(component.props.indentFirstLine, 0);
  return {
    ...resolveFillStyle(component),
    borderStyle: component.props.lineStyle === "none" ? "none" : component.props.lineStyle || "solid",
    borderColor: component.props.lineColor || undefined,
    borderWidth: component.props.lineStyle === "none" ? 0 : numberValue(component.props.lineWidth, 1),
    borderRadius: numberValue(component.props.cornerRadius, 2),
    paddingTop: numberValue(component.props.paddingTop, 2),
    paddingRight: numberValue(component.props.paddingRight, 4) + indentRight,
    paddingBottom: numberValue(component.props.paddingBottom, 2),
    paddingLeft: numberValue(component.props.paddingLeft, 4) + indentLeft,
    color: component.props.textColor || undefined,
    fontFamily: component.props.fontFamily || undefined,
    fontSize: numberValue(component.props.fontSize, 14),
    fontWeight: cssFontWeight(component.props.fontWeight),
    fontStyle: cssFontStyle(component.props.fontWeight),
    textDecoration: component.props.textUnderline ? "underline" : undefined,
    textAlign: component.props.textAlign || undefined,
    lineHeight: lineSpacingUnits === "pt" ? `${lineSpacingValue}px` : lineSpacingValue,
    textIndent: indentFirstLine === 0 ? undefined : `${indentFirstLine}px`
  };
}

function shapePreviewStyle(component: LayoutComponent): CSSProperties {
  const shapeType = component.props.shapeType ?? "rectangle";
  const lineWidth = Math.max(1, numberValue(component.props.lineWidth, shapeType === "line" ? 2 : 1));
  const lineStyle = component.props.lineStyle ?? "solid";
  const lineColor = component.props.lineColor || "#94a3b8";
  const cornerRadius = numberValue(component.props.cornerRadius, shapeType === "roundedRectangle" ? 12 : 0);

  if (shapeType === "line") {
    const horizontal = component.position.width >= component.position.height;
    if (horizontal) {
      return {
        background: "transparent",
        borderTopStyle: lineStyle === "none" ? "solid" : lineStyle,
        borderTopWidth: lineStyle === "none" ? 0 : lineWidth,
        borderTopColor: lineColor,
        borderRadius: 0
      };
    }
    return {
      background: "transparent",
      borderLeftStyle: lineStyle === "none" ? "solid" : lineStyle,
      borderLeftWidth: lineStyle === "none" ? 0 : lineWidth,
      borderLeftColor: lineColor,
      borderRadius: 0
    };
  }

  return {
    borderStyle: lineStyle === "none" ? "none" : lineStyle,
    borderWidth: lineStyle === "none" ? 0 : lineWidth,
    borderColor: lineColor,
    ...resolveFillStyle(component, {
      defaultFillType: "solid",
      defaultFillColor: "#f8fafc"
    }),
    borderRadius: shapeType === "oval" ? 9999 : cornerRadius
  };
}

function cloneLayoutDefinition(layout: LayoutDefinition): LayoutDefinition {
  if (typeof structuredClone === "function") {
    return structuredClone(layout);
  }
  return JSON.parse(JSON.stringify(layout)) as LayoutDefinition;
}

function isEditableTarget(target: EventTarget | null): boolean {
  if (!(target instanceof HTMLElement)) {
    return false;
  }
  const tag = target.tagName.toLowerCase();
  return (
    target.isContentEditable ||
    tag === "input" ||
    tag === "textarea" ||
    tag === "select" ||
    tag === "button"
  );
}

function styleToken(value: string | undefined): string {
  const raw = (value ?? "").trim().toLowerCase();
  if (!raw) {
    return "default";
  }
  return raw.replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "") || "default";
}

function normalizeStyleTargetLabels(values: string[] | undefined): string[] {
  if (!Array.isArray(values)) {
    return [];
  }
  const deduped: string[] = [];
  const seen = new Set<string>();
  for (const value of values) {
    const cleaned = String(value ?? "").trim();
    if (!cleaned) {
      continue;
    }
    const token = cleaned.toLowerCase();
    if (seen.has(token)) {
      continue;
    }
    seen.add(token);
    deduped.push(cleaned);
  }
  return deduped;
}

function inferStyleTargetsFromName(styleName: string): string[] {
  const matches = fileMakerStyleTargetMatchers
    .filter((entry) => entry.pattern.test(styleName))
    .map((entry) => entry.label);
  return normalizeStyleTargetLabels(matches);
}

function buildThemeStyleGroups(
  styleNames: string[],
  styleTargetsByLowerStyleName: Record<string, string[]>
): ThemeStyleGroup[] {
  const groups = new Map<string, string[]>();
  const addStyleToGroup = (groupLabel: string, styleName: string) => {
    const list = groups.get(groupLabel) ?? [];
    if (!list.some((entry) => entry.toLowerCase() === styleName.toLowerCase())) {
      list.push(styleName);
    }
    groups.set(groupLabel, list);
  };

  for (const styleName of styleNames) {
    const catalogTargets = normalizeStyleTargetLabels(styleTargetsByLowerStyleName[styleName.toLowerCase()]);
    const targets = catalogTargets.length > 0 ? catalogTargets : inferStyleTargetsFromName(styleName);
    const resolvedTargets = targets.length > 0 ? targets : ["General"];
    for (const target of resolvedTargets) {
      addStyleToGroup(target, styleName);
    }
  }

  const knownOrder = [...fileMakerStyleGroupOrder];
  const orderedLabels = [
    ...knownOrder.filter((label) => groups.has(label)),
    ...[...groups.keys()]
      .filter((label) => !knownOrder.includes(label as (typeof fileMakerStyleGroupOrder)[number]))
      .sort((left, right) => left.localeCompare(right, undefined, { sensitivity: "base" }))
  ];

  return orderedLabels.map((label) => ({
    id: styleToken(label),
    label,
    styles: groups.get(label) ?? []
  }));
}

function isUniversalTouchTheme(value: string | undefined): boolean {
  return (value ?? "").toLowerCase().includes("universal touch");
}

function normalizeCanvasDevicePresetIds(canvas: LayoutDefinition["canvas"] | undefined): string[] {
  if (!canvas) {
    return [];
  }
  const knownPresetIds = new Set(layoutDevicePresets.map((preset) => preset.id));
  const next: string[] = [];
  const seen = new Set<string>();
  const pushPreset = (raw: string | null | undefined) => {
    const presetId = String(raw ?? "").trim();
    if (!presetId || presetId === "custom" || !knownPresetIds.has(presetId) || seen.has(presetId)) {
      return;
    }
    seen.add(presetId);
    next.push(presetId);
  };
  if (Array.isArray(canvas.deviceFramePresetIds) && canvas.deviceFramePresetIds.length > 0) {
    for (const presetId of canvas.deviceFramePresetIds) {
      pushPreset(presetId);
    }
    return next;
  }
  pushPreset(canvas.devicePresetId);
  return next;
}

function normalizeCanvasCustomFrame(
  canvas: LayoutDefinition["canvas"] | undefined
): { width: number; height: number } | null {
  if (!canvas) {
    return null;
  }
  const explicitCustomWidth = Math.max(0, Math.round(Number(canvas.deviceFrameCustomWidth) || 0));
  const explicitCustomHeight = Math.max(0, Math.round(Number(canvas.deviceFrameCustomHeight) || 0));
  if (explicitCustomWidth > 0 && explicitCustomHeight > 0) {
    return {
      width: explicitCustomWidth,
      height: explicitCustomHeight
    };
  }
  const legacyPreset = (canvas.devicePresetId ?? "").trim();
  if (legacyPreset !== "custom") {
    return null;
  }
  const legacyWidth = Math.max(0, Math.round(Number(canvas.deviceFrameWidth) || 0));
  const legacyHeight = Math.max(0, Math.round(Number(canvas.deviceFrameHeight) || 0));
  if (legacyWidth > 0 && legacyHeight > 0) {
    return {
      width: legacyWidth,
      height: legacyHeight
    };
  }
  return null;
}

function inferCanvasDevicePresetId(canvas: LayoutDefinition["canvas"] | undefined): string {
  const selectedPresetIds = normalizeCanvasDevicePresetIds(canvas);
  if (selectedPresetIds.length > 0) {
    return selectedPresetIds[0];
  }
  if (normalizeCanvasCustomFrame(canvas)) {
    return "custom";
  }
  return "custom";
}

function resolveCanvasDeviceFrames(
  canvas: LayoutDefinition["canvas"] | undefined
): Array<{ id: string; label: string; width: number; height: number; isCustom: boolean }> {
  if (!canvas) {
    return [];
  }
  const selectedPresetIds = normalizeCanvasDevicePresetIds(canvas);
  const presetFrames = selectedPresetIds
    .map((presetId) => {
      const preset = layoutDevicePresets.find((entry) => entry.id === presetId);
      if (!preset) {
        return null;
      }
      return {
        id: preset.id,
        label: preset.label,
        width: preset.width,
        height: preset.height,
        isCustom: false
      };
    })
    .filter(
      (
        frame
      ): frame is {
        id: string;
        label: string;
        width: number;
        height: number;
        isCustom: false;
      } => frame !== null
    );
  const customFrame = normalizeCanvasCustomFrame(canvas);
  if (!customFrame) {
    return presetFrames;
  }
  return [
    ...presetFrames,
    {
      id: "custom",
      label: `Custom: ${canvasDimensionLabel(customFrame.width, customFrame.height)}`,
      width: customFrame.width,
      height: customFrame.height,
      isCustom: true
    }
  ];
}

function resolveCanvasDeviceFrame(
  canvas: LayoutDefinition["canvas"] | undefined
): { width: number; height: number } | null {
  const frames = resolveCanvasDeviceFrames(canvas);
  if (frames.length === 0) {
    return null;
  }
  const first = frames[0];
  return {
    width: first.width,
    height: first.height
  };
}

function canvasDimensionLabel(width: number, height: number): string {
  return `${Math.max(1, Math.round(width))} x ${Math.max(1, Math.round(height))}`;
}

function layoutPartTypeLabel(type: LayoutPartType): string {
  const option = layoutPartTypeOptions.find((entry) => entry.type === type);
  return option?.label ?? "Part";
}

function layoutPartTooltip(part: { type: LayoutPartType; label?: string; sortByField?: string }): string {
  const typeLabel = layoutPartTypeLabel(part.type);
  const customLabel = (part.label ?? "").trim();
  if (part.type === "subSummary") {
    const sortBy = (part.sortByField ?? "").trim();
    if (sortBy) {
      return `Sub-summary when sorted by ${sortBy}`;
    }
  }
  if (customLabel && customLabel.toLowerCase() !== typeLabel.toLowerCase()) {
    return `${customLabel} (${typeLabel})`;
  }
  return customLabel || typeLabel;
}

function isSummaryPartType(type: LayoutPartType): boolean {
  return type === "leadingGrandSummary" || type === "subSummary" || type === "trailingGrandSummary";
}

function normalizeLayoutParts(layout: LayoutDefinition | null): NormalizedLayoutPart[] {
  if (!layout) {
    return [];
  }

  const rawParts =
    layout.parts && layout.parts.length > 0
      ? layout.parts
      : [
          {
            id: "part-body-default",
            type: "body" as const,
            label: "Body",
            height: layout.canvas.height
          }
        ];

  const usableParts = rawParts.filter((part) => part && Number(part.height) > 0);
  const orderedParts = [...usableParts].sort((left, right) => {
    const orderDiff = layoutPartOrder.indexOf(left.type) - layoutPartOrder.indexOf(right.type);
    if (orderDiff !== 0) {
      return orderDiff;
    }
    return left.id.localeCompare(right.id);
  });

  let top = 0;
  return orderedParts.map((part, index) => {
    const height = Math.max(20, Math.round(Number(part.height) || 20));
    const normalized: NormalizedLayoutPart = {
      ...part,
      label: (part.label ?? layoutPartTypeLabel(part.type)).trim() || layoutPartTypeLabel(part.type),
      height,
      top,
      bottom: top + height,
      index
    };
    top += height;
    return normalized;
  });
}

function findLayoutPartForY(parts: NormalizedLayoutPart[], y: number): NormalizedLayoutPart | null {
  if (parts.length === 0) {
    return null;
  }
  const clampedY = Math.max(0, y);
  for (const part of parts) {
    if (clampedY >= part.top && clampedY < part.bottom) {
      return part;
    }
  }
  return parts[parts.length - 1] ?? null;
}

function popoverIconGlyph(icon: PopoverButtonIcon | undefined): string {
  switch (icon) {
    case "chevronLeft":
      return "◁";
    case "chevronRight":
      return "▷";
    case "home":
      return "H";
    case "comment":
    default:
      return "o";
  }
}

function normalizeChartType(value: string | undefined): FileMakerChartType {
  const normalized = (value ?? "").trim().toLowerCase();
  const found = FILEMAKER_CHART_TYPE_OPTIONS.find((entry) => entry.value === normalized);
  return found?.value ?? "column";
}

function normalizeChartSummary(value: string | undefined): FileMakerChartSummaryType {
  const normalized = (value ?? "").trim().toLowerCase();
  const found = FILEMAKER_CHART_SUMMARY_OPTIONS.find((entry) => entry.value === normalized);
  return found?.value ?? "count";
}

const styleClipboardKeys: Array<keyof LayoutComponent["props"]> = [
  "styleTheme",
  "styleName",
  "fillType",
  "fillColor",
  "fillGradientStartColor",
  "fillGradientEndColor",
  "fillGradientAngle",
  "fillImageUrl",
  "lineStyle",
  "lineWidth",
  "lineColor",
  "cornerRadius",
  "effectOuterShadow",
  "effectInnerShadow",
  "paddingTop",
  "paddingRight",
  "paddingBottom",
  "paddingLeft",
  "fontFamily",
  "fontWeight",
  "fontSize",
  "textColor",
  "textUnderline",
  "textAlign",
  "lineSpacing",
  "lineSpacingHeight",
  "lineSpacingAbove",
  "lineSpacingBelow",
  "lineSpacingUnits",
  "indentFirstLine",
  "indentLeft",
  "indentRight",
  "indentUnits",
  "tabStops",
  "tabAlignment",
  "tabAlignOn",
  "tabLeader",
  "baseline",
  "baselineOffset",
  "variant",
  "rotation"
];

function snapshotObjectStyleProps(component: LayoutComponent): Partial<LayoutComponent["props"]> {
  const snapshot: Partial<LayoutComponent["props"]> = {};
  const snapshotRecord = snapshot as Record<string, unknown>;
  for (const key of styleClipboardKeys) {
    const value = component.props[key];
    if (typeof value === "undefined") {
      continue;
    }
    if (Array.isArray(value)) {
      snapshotRecord[key] = [...value];
      continue;
    }
    snapshotRecord[key] = value;
  }
  return snapshot;
}

type EditableTarget = HTMLInputElement | HTMLTextAreaElement | HTMLElement;

function resolveActiveEditableTarget(): EditableTarget | null {
  if (typeof document === "undefined") {
    return null;
  }
  const active = document.activeElement;
  if (!(active instanceof HTMLElement)) {
    return null;
  }
  if (active instanceof HTMLInputElement) {
    const editableTypes = new Set([
      "",
      "text",
      "search",
      "url",
      "tel",
      "email",
      "password",
      "number"
    ]);
    if (active.readOnly || active.disabled || !editableTypes.has((active.type ?? "").toLowerCase())) {
      return null;
    }
    return active;
  }
  if (active instanceof HTMLTextAreaElement) {
    if (active.readOnly || active.disabled) {
      return null;
    }
    return active;
  }
  if (active.isContentEditable) {
    return active;
  }
  return null;
}

function dispatchInputEvent(target: EditableTarget): void {
  target.dispatchEvent(new Event("input", { bubbles: true }));
  target.dispatchEvent(new Event("change", { bubbles: true }));
}

function insertPlainTextIntoTarget(target: EditableTarget, text: string): boolean {
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    const start = target.selectionStart ?? target.value.length;
    const end = target.selectionEnd ?? start;
    target.setRangeText(text, start, end, "end");
    dispatchInputEvent(target);
    return true;
  }
  if (typeof document !== "undefined" && typeof document.execCommand === "function") {
    target.focus();
    const inserted = document.execCommand("insertText", false, text);
    if (inserted) {
      dispatchInputEvent(target);
      return true;
    }
  }
  target.textContent = `${target.textContent ?? ""}${text}`;
  dispatchInputEvent(target);
  return true;
}

function clearEditableTarget(target: EditableTarget): boolean {
  if (target instanceof HTMLInputElement || target instanceof HTMLTextAreaElement) {
    target.value = "";
    dispatchInputEvent(target);
    return true;
  }
  target.textContent = "";
  dispatchInputEvent(target);
  return true;
}

function layoutPreviewClasses(component: LayoutComponent): string {
  const classes = [
    `runtime-item-type-${component.type}`,
    `runtime-style-${styleToken(component.props.styleName)}`,
    `runtime-variant-${component.props.variant ?? "primary"}`
  ];
  if (component.type === "button") {
    classes.push(`runtime-button-mode-${component.props.buttonMode ?? "standard"}`);
  }
  if (component.type === "panel") {
    classes.push(`runtime-panel-type-${component.props.panelType ?? "tab"}`);
  }
  if (isUniversalTouchTheme(component.props.styleTheme)) {
    classes.push("runtime-theme-universal-touch");
  }
  return classes.join(" ");
}

function detectShortcutDocsPlatform(): ShortcutDocsPlatform {
  if (typeof navigator === "undefined") {
    return "unknown";
  }
  const navigatorWithUAData = navigator as Navigator & { userAgentData?: { platform?: string } };
  const platform = navigatorWithUAData.userAgentData?.platform || navigator.platform || "";
  const userAgent = navigator.userAgent || "";
  const touchPoints = Number(navigator.maxTouchPoints || 0);
  const hasTouch = touchPoints > 0;
  const isIPhone = /iPhone|iPod/i.test(userAgent);
  const isIPad = /iPad/i.test(userAgent) || (hasTouch && /Mac/i.test(platform));
  if (isIPhone || isIPad || /Android|Mobile|Tablet/i.test(userAgent)) {
    return "mobile";
  }
  if (/Win/i.test(platform) || /Windows/i.test(userAgent)) {
    return "windows";
  }
  if (/Mac|Intel Mac/i.test(platform) || /Macintosh|Mac OS X/i.test(userAgent)) {
    return "mac";
  }
  return "unknown";
}

function keyboardShortcutsDocsUrl(platform: ShortcutDocsPlatform): string {
  if (platform === "windows") {
    return HELP_URL_SHORTCUTS_WINDOWS;
  }
  return HELP_URL_SHORTCUTS_MAC;
}

function filterHelpMenuEntries(searchTerm: string): HelpMenuEntry[] {
  const normalized = searchTerm.trim().toLowerCase();
  if (!normalized) {
    return helpMenuEntries;
  }
  const raw = helpMenuEntries.filter((entry) => {
    if (entry.kind === "divider") {
      return true;
    }
    const text = `${entry.label} ${entry.keywords}`.toLowerCase();
    return text.includes(normalized);
  });
  const cleaned: HelpMenuEntry[] = [];
  for (let index = 0; index < raw.length; index += 1) {
    const entry = raw[index];
    if (entry.kind === "divider") {
      const hasPreviousAction = cleaned.length > 0 && cleaned[cleaned.length - 1]?.kind === "action";
      if (!hasPreviousAction) {
        continue;
      }
      const hasNextAction = raw.slice(index + 1).some((candidate) => candidate.kind === "action");
      if (!hasNextAction) {
        continue;
      }
    }
    cleaned.push(entry);
  }
  while (cleaned.length > 0 && cleaned[0]?.kind === "divider") {
    cleaned.shift();
  }
  while (cleaned.length > 0 && cleaned[cleaned.length - 1]?.kind === "divider") {
    cleaned.pop();
  }
  return cleaned;
}

function normalizeWorkspaceToken(value: string | undefined): string {
  const cleaned = String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_-]+/g, "-")
    .replace(/^-+|-+$/g, "");
  return cleaned || "default";
}

function withWorkspaceQuery(pathname: string, workspaceId: string): string {
  const separator = pathname.includes("?") ? "&" : "?";
  return `${pathname}${separator}workspace=${encodeURIComponent(workspaceId)}`;
}

function replaceWorkspaceQuery(pathname: string, workspaceId: string): string {
  const [path, rawQuery = ""] = pathname.split("?");
  const params = new URLSearchParams(rawQuery);
  params.set("workspace", normalizeWorkspaceToken(workspaceId));
  const query = params.toString();
  return query ? `${path}?${query}` : path;
}

function dedupeWorkspaceIds(values: string[]): string[] {
  const deduped: string[] = [];
  const seen = new Set<string>();
  for (const value of values) {
    const normalized = normalizeWorkspaceToken(value);
    if (seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    deduped.push(normalized);
  }
  return deduped;
}

function workspaceHostLabel(value: string | null | undefined): string {
  const raw = String(value ?? "").trim();
  if (!raw) {
    return "";
  }
  try {
    const normalized = raw.includes("://") ? raw : `https://${raw}`;
    const parsed = new URL(normalized);
    return parsed.host || raw;
  } catch {
    const withoutProtocol = raw.replace(/^[a-z]+:\/\//i, "");
    const host = withoutProtocol.split(/[/?#]/)[0]?.trim() ?? "";
    return host || raw;
  }
}

