    setFieldDraw(null);
    setWebViewerDraw(null);
    setChartDraw(null);
    setPanelToolsOpen(false);
    setTextToolsOpen(false);
    setShapeToolsOpen(false);
    setFieldToolsOpen(false);
    setContextMenu(null);
    setContextSubmenu(null);
    setActiveTextTool(null);
    setActiveShapeTool(null);
    setActiveFieldTool(null);
    setActivePanelTool(null);
    setActiveWebViewerTool(false);
    setActiveChartTool(false);
